#include <stdio.h>
#include <stdlib.h>

int main() {
    int testCase;
    scanf("%d", &testCase);

    while (testCase--) {
        long long n;
        scanf("%lld", &n);

        long long ans = 1;

        // Allocate dynamic arrays
        long long *arr = (long long *)malloc(n * sizeof(long long));
        long long *dp = (long long *)malloc(n * sizeof(long long));

        // Initialize dp array to 1
        for (long long i = 0; i < n; i++) {
            dp[i] = 1;
        }

        // Read array elements
        for (long long i = 0; i < n; i++) {
            scanf("%lld", &arr[i]);
        }

        // Calculate dp values and final answer
        for (long long i = 1; i < n; i++) {
            if (arr[i - 1] <= arr[i]) {
                dp[i] += dp[i - 1];
            }

            ans += dp[i];
        }

        printf("%lld\n", ans);

        // Free allocated memory
        free(arr);
        free(dp);
    }

    return 0;
}

