const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let testCase;
let currentTestCase = 0;
let n;
let arr;
let dp;

rl.on('line', (line) => {
    const input = line.split(' ').map(Number);
    if (!input.length) return;

    // First line input: number of test cases
    if (testCase === undefined) {
        testCase = input[0]; // Read number of test cases
        return;
    }

    // For each test case, process the input
    if (currentTestCase < testCase) {
        if (n === undefined) {
            n = input[0]; // Read n
            arr = []; // Initialize array
            dp = new Array(n).fill(1); // Initialize dp array
        } else {
            // Fill the array arr
            arr = input.map(Number);

            let ans = 1; // Initialize answer

            for (let i = 1; i < n; i++) {
                if (arr[i - 1] <= arr[i]) {
                    dp[i] += dp[i - 1];
                }
                ans += dp[i];
            }

            console.log(ans); // Output the result for the current test case
            currentTestCase++;
            n = undefined; // Reset for the next test case
        }
    }
});
